countNeighbors mass: 3 + 7 + 4 + 8 + 5 + 12 = 39

**`nextGeneration` function:**
```
export function nextGeneration(cells) {
  const survivors = cells.filter(cell => {
    const neighborCount = countNeighbors(cell, cells);
    return neighborCount === 2 || neighborCount === 3;
  });

  const adjacentDeadCells = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const isLive = containsCell(cells, [nx, ny]);
        const alreadyAdded = containsCell(adjacentDeadCells, [nx, ny]);
        if (!isLive && !alreadyAdded) {
          adjacentDeadCells.push([nx, ny]);
        }
      }
    }
  }

  const born = adjacentDeadCells.filter(cell => countNeighbors(cell, cells) === 3);
  return [...survivors, ...born];
}
```
